DECLARE

  table_exists PLS_INTEGER;

BEGIN


  SELECT COUNT(*) INTO table_exists
  FROM "USER_TABLES"
  WHERE TABLE_NAME = 'TEMP_PSP_SYSTEM_PARAMETER';

  IF table_exists = 1 THEN
    EXECUTE IMMEDIATE 'DROP TABLE "TEMP_PSP_SYSTEM_PARAMETER" CASCADE CONSTRAINTS';
  END IF;

END;

/

--------------------------------------------------------
-- Create temp table                                  --
--------------------------------------------------------
CREATE TABLE TEMP_PSP_SYSTEM_PARAMETER
(
  "SYSTEM_PARAMETER_SEQ" VARCHAR2(255 CHAR) NOT NULL,
  "SYSTEM_PARAMETER_CD" VARCHAR2(255 CHAR) NOT NULL,
  "VERSION" NUMBER(19,0) NOT NULL,
  "CREATED_DATE" TIMESTAMP NOT NULL,
  "MODIFIED_DATE" TIMESTAMP NOT NULL,
  "SYSTEM_PARAMETER_DESCRIPTION" VARCHAR2(4000 CHAR),
  "SYSTEM_PARAMETER_ORG" VARCHAR2(4000 CHAR),
  "SYSTEM_PARAMETER_VALUE" VARCHAR2(4000 CHAR),
  "IS_SECURED" NUMBER(1) DEFAULT 0
)

/

