--------------------------------------------------------
-- Sychronize temp table and real table by            --
-- inserting, deleting, and updating as necessary     --
--------------------------------------------------------

DELETE FROM PSP_SYSTEM_PARAMETER
WHERE SYSTEM_PARAMETER_CD NOT IN (SELECT SYSTEM_PARAMETER_CD FROM TEMP_PSP_SYSTEM_PARAMETER)
      AND SYSTEM_PARAMETER_CD NOT LIKE 'UNCOMPRESSED_OFX_%'
/

INSERT INTO PSP_SYSTEM_PARAMETER
(SYSTEM_PARAMETER_SEQ, CREATED_DATE, MODIFIED_DATE, SYSTEM_PARAMETER_CD, SYSTEM_PARAMETER_VALUE, SYSTEM_PARAMETER_DESCRIPTION, SYSTEM_PARAMETER_ORG, VERSION, IS_SECURED)
  SELECT
    SYSTEM_PARAMETER_SEQ, CREATED_DATE, MODIFIED_DATE, SYSTEM_PARAMETER_CD, SYSTEM_PARAMETER_VALUE, SYSTEM_PARAMETER_DESCRIPTION, SYSTEM_PARAMETER_ORG, VERSION, IS_SECURED
  FROM
    TEMP_PSP_SYSTEM_PARAMETER tt
  WHERE
    tt.SYSTEM_PARAMETER_CD NOT IN (SELECT SYSTEM_PARAMETER_CD FROM PSP_SYSTEM_PARAMETER)
/

UPDATE PSP_SYSTEM_PARAMETER rt
SET ( rt.CREATED_DATE, rt.MODIFIED_DATE, rt.SYSTEM_PARAMETER_DESCRIPTION, rt.SYSTEM_PARAMETER_ORG, rt.VERSION, rt.IS_SECURED) =
(SELECT  tt.CREATED_DATE, tt.MODIFIED_DATE, tt.SYSTEM_PARAMETER_DESCRIPTION, tt.SYSTEM_PARAMETER_ORG, tt.VERSION, tt.IS_SECURED
FROM TEMP_PSP_SYSTEM_PARAMETER tt WHERE tt.SYSTEM_PARAMETER_CD = rt.SYSTEM_PARAMETER_CD)
WHERE SYSTEM_PARAMETER_CD NOT LIKE 'UNCOMPRESSED_OFX_%'
/
--As part of   PSP-10846   made this to  -1.
UPDATE PSP_SYSTEM_PARAMETER rt
SET  rt.SYSTEM_PARAMETER_VALUE= '-1'
WHERE SYSTEM_PARAMETER_CD = 'IOP_SYNC_THREAD_POOL_MAX_WAIT'
/
--PSRV000657... don't reset AS400_TOKEN when redeploying 
--PSRV000886... don't reset any system parameter _value_ when deploying - they are meant to be modifiable in each environment


UPDATE PSP_SYSTEM_PARAMETER rt
SET  rt.SYSTEM_PARAMETER_VALUE= 'Standard:40%  off for 6 months,PAP Price:NULL,Costco:NULL',
rt.MODIFIER_ID='PSP-21078',rt.MODIFIED_DATE = SYS_EXTRACT_UTC(systimestamp)
WHERE SYSTEM_PARAMETER_CD = 'ENTITLED_OFFER_CODE'
/

UPDATE PSP_SYSTEM_PARAMETER rt
SET  rt.SYSTEM_PARAMETER_VALUE= '1',
rt.MODIFIER_ID='next-day-payroll',rt.MODIFIED_DATE = SYS_EXTRACT_UTC(systimestamp)
WHERE SYSTEM_PARAMETER_CD = 'ACH_TAX_PAYMENT_FILE_SETTLEMENT_DATE_OFFSET'
/

